import { CommonModule } from '@angular/common';
import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { PublicProduct } from '../models';

@Component({
  selector: 'app-product-card',
  standalone: true,
  imports: [CommonModule, RouterLink],
  template: `
    <article class="card">
      <h3 class="card__title">{{ product.nombre }}</h3>
      <p class="card__meta" *ngIf="product.descuento_tipo; else noDiscount">
        Descuento:
        <strong *ngIf="product.descuento_tipo === 'porcentaje'; else fixedDiscount">
          {{ product.descuento_valor }}%
        </strong>
        <ng-template #fixedDiscount>
          <strong>S/ {{ product.descuento_valor }}</strong>
        </ng-template>
      </p>
      <ng-template #noDiscount>
        <p class="card__meta">Sin descuento aplicable</p>
      </ng-template>

      <p><strong>S/ {{ product.precio_descuento | number:'1.2-2' }}</strong></p>

      <p class="card__meta" *ngIf="product.cuotas_sin_interes">
        Hasta 12 cuotas sin interés de S/ {{ product.cuotas_mensual | number:'1.2-2' }}
      </p>
      <p class="card__meta" *ngIf="product.envio_gratis">Envío gratis</p>

      <div style="display:flex; justify-content:flex-end; margin-top:1rem;">
        <a class="back-link" [routerLink]="['/producto', product.id]">Ver producto</a>
      </div>
    </article>
  `,
})
export class ProductCardComponent {
  @Input({ required: true }) product!: PublicProduct;
}
